example.code:
// Good: role-based — survives class renames and DOM moves
await page.getByRole('button', { name: 'Submit' }).click();
await page.getByLabel('Email address').fill('user@example.com');
await page.getByText('Sign in').click();

// Only use CSS when no semantic role exists
await page.locator('[data-testid="custom-widget"]').click();

// Good: auto-wait built into locator actions
await page.getByRole('button', { name: 'Load' }).click();
await expect(page.getByRole('table')).toBeVisible();

// Good: explicit wait when load state matters
await page.goto('/dashboard');
await page.waitForLoadState('networkidle');
